mapper.select:
SELECT scene.name sceneName, area.name areaName, ap.name apName, es.time, IFNULL((es.speed),0) speed FROM scene LEFT JOIN experiencespeed es ON es.`sceneId`=scene.`id` LEFT JOIN area ON es.`areaId`=area.`id` LEFT JOIN ap on es.`apId`=ap.`id` where 1=1
and scene.id=#{sceneId}
order by scene.id

SELECT scene.name sceneName, area.name areaName, ap.name apName, es.time, IFNULL((es.speed),0) speed FROM area LEFT JOIN experiencespeed es ON es.`areaId`=area.`id` LEFT JOIN scene ON es.`sceneId`=scene.`id` LEFT JOIN ap on es.`apId`=ap.`id` where 1=1
and area.sceneId=#{sceneId}
order by scene.id

SELECT scene.name sceneName, area.name areaName, ap.name apName, es.time, IFNULL((es.speed),0) speed FROM ap LEFT JOIN experiencespeed es ON es.`apId`=ap.`id` LEFT JOIN scene ON es.`sceneId`=scene.`id` LEFT JOIN area on es.`areaId`=area.`id` where 1=1
and ap.areaId=#{areaId}
order by scene.id

SELECT ap.id,ap.name apName,scene.name sceneName, area.name areaName FROM experiencespeed es LEFT JOIN scene ON scene.id=es.sceneId LEFT JOIN area ON es.areaId=area.id LEFT JOIN ap ON es.apId=ap.id WHERE 1=1
and scene.name IS NOT NULL
and scene.name IS NOT NULL and scene.id=#{sceneId}
and area.name IS NOT NULL and area.id=#{areaId}

SELECT es.`id`, es.`platform`, es.`speed`, es.`time`, es.`address`, es.`macAddress`, es.`macAddress5G`, es.`sceneId`, es.`areaId`, es.`apId`, es.`speedometer`, scene.`name` sceneName, area.`name` areaName, ap.`name` apName FROM experiencespeed es LEFT JOIN scene ON es.sceneId=scene.id LEFT JOIN area ON es.areaId =area.id LEFT JOIN ap ON es.apId=ap.id WHERE 1=1 and es.speed >= ${networkPassValue}
AND scene.name=#{sceneName}
AND area.name=#{areaName}
AND ap.name=#{apName}

SELECT es.`id`, es.`platform`, es.`speed`, es.`time`, es.`address`, es.`macAddress`, es.`macAddress5G`, es.`sceneId`, es.`areaId`, es.`apId`, es.`speedometer`, scene.`name` sceneName, area.`name` areaName, ap.`name` apName FROM experiencespeed es LEFT JOIN scene ON es.sceneId=scene.id LEFT JOIN area ON es.areaId =area.id LEFT JOIN ap ON es.apId=ap.id WHERE 1=1 and es.speed < ${networkPassValue}
AND scene.name=#{sceneName}
AND area.name=#{areaName}
AND ap.name=#{apName}

SELECT es.`id`, es.`platform`, es.`speed`, es.`time`, es.`address`, es.`macAddress`, es.`macAddress5G`, es.`sceneId`, es.`areaId`, es.`apId`, es.`speedometer`, scene.`name` sceneName, area.`name` areaName, ap.`name` apName FROM experiencespeed es LEFT JOIN scene ON es.sceneId=scene.id LEFT JOIN area ON es.areaId =area.id LEFT JOIN ap ON es.apId=ap.id WHERE 1=1
AND scene.name=#{sceneName}
AND area.name=#{areaName}
AND ap.name=#{apName}
